mapper.select:
SELECT p.id, p.project_name AS projectName, p.leader_user_id AS leaderUserId, COALESCE(NULLIF(u.real_name, ''), u.username) AS leaderName, p.start_date AS startDate, p.plan_end_date AS planEndDate, p.status AS status, p.done_at AS doneAt, p.done_by_user_id AS doneByUserId, COALESCE(m.cnt, 0) AS memberCount FROM dept_daily_project p LEFT JOIN sys_user u ON u.tenant_id = p.tenant_id AND u.id = p.leader_user_id LEFT JOIN ( SELECT tenant_id, project_id, COUNT(1) AS cnt FROM dept_daily_project_member WHERE is_active = 1 GROUP BY tenant_id, project_id ) m ON m.tenant_id = p.tenant_id AND m.project_id = p.id WHERE p.tenant_id = #{tenantId}
AND p.dept_id = #{deptId}
AND p.office_id = #{officeId}
AND p.start_date >= CONCAT(#{year}, '-01-01') AND p.start_date <= CONCAT(#{year}, '-12-31')
AND p.status = #{status}
AND p.project_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.start_date DESC, p.id DESC
